// Merge Postgres result with webhook body
const dbRows = $input.all();
const body = $('Webhook - Sofia Conversion').first().json.body || {};

if (!dbRows.length || !dbRows[0].json?.click_id) {
  return [{ json: { valid: false, reason: 'attribution_not_found' } }];
}

const db = dbRows[0].json;

// Skip if already uploaded (idempotency guard)
if (db.conversion_uploaded_at) {
  return [{ json: { valid: false, reason: 'already_uploaded', click_id: db.click_id } }];
}

return [{
  json: {
    valid: true,
    // From webhook body
    conversion_type: body.conversion_type || 'appointment',
    attribution_id: body.attribution_id,
    clinic_id: body.clinic_id,
    service_name: body.service_name || '',
    scheduled_at: body.scheduled_at || new Date().toISOString(),
    conversion_value_brl: parseFloat(body.conversion_value_brl) || 0,
    // From DB
    click_id: db.click_id,
    gclid: db.gclid,
    fbclid: db.fbclid,
    resolved_jid: db.resolved_jid,
    clicked_at: db.clicked_at,
    // Google Ads
    google_ads_enabled: db.google_ads_enabled === true,
    google_ads_customer_id: db.google_ads_customer_id,
    google_ads_developer_token: db.google_ads_developer_token,
    google_ads_refresh_token: db.google_ads_refresh_token,
    google_conversion_action_appointment: db.google_conversion_action_appointment,
    // Meta
    meta_enabled: db.meta_enabled === true,
    meta_pixel_id: db.meta_pixel_id,
    meta_access_token: db.meta_access_token,
    meta_test_event_code: db.meta_test_event_code
  }
}];

// Merge access_token from OAuth response back with main payload
const oauthResp = $input.first().json;
const payload = $('Montar Payload').first().json;

const accessToken = oauthResp.access_token || oauthResp.body?.access_token || '';

// Format conversion datetime: Google requires 'yyyy-MM-dd HH:mm:ssZ'
const dt = new Date(payload.scheduled_at);
const pad = n => String(n).padStart(2, '0');
const conversionDateTime =
  `${dt.getFullYear()}-${pad(dt.getMonth()+1)}-${pad(dt.getDate())} ` +
  `${pad(dt.getHours())}:${pad(dt.getMinutes())}:${pad(dt.getSeconds())}+0000`;

return [{
  json: {
    ...payload,
    google_access_token: accessToken,
    conversion_date_time: conversionDateTime
  }
}];

