// Hash phone number (E.164 digits only) with SHA256 for Meta CAPI
const payload = $('Montar Payload').first().json;
const crypto = require('crypto');

const jid = payload.resolved_jid || '';
const phone = jid.split('@')[0].replace(/\D/g, '');
const hashedPhone = phone ? crypto.createHash('sha256').update(phone).digest('hex') : '';

const eventTimeUnix = Math.floor(new Date(payload.scheduled_at).getTime() / 1000);

return [{
  json: {
    ...payload,
    hashed_phone: hashedPhone,
    event_time: eventTimeUnix
  }
}];

parameters.jsonBody:
