    },
    custom_data: {
      value: $json.conversion_value_brl,
      currency: 'BRL',
      content_name: $json.service_name
    },
    action_source: 'other'
  }],
  access_token: $json.meta_access_token,
  test_event_code: $json.meta_test_event_code || undefined
}) }}
